#!/usr/bin/env python3
# writer.py — Myra soul S1: swap MYRA_SOUL for Dev's authored "perfect manager" rework.
# Folded verbatim EXCEPT the opening "You are Myra—" rides the {{ASSISTANT_NAME}}
# placeholder (Dev's call) so the owner's chosen name folds in at runtime (default Myra).
# The myraSoul(assistantName) builder, the substitution, and the export are preserved.
# Guarded + idempotent.
import base64, os, sys

TARGET = os.path.join("src", "agent", "myraSoul.js")
OLD_B64 = ""
NEW_B64 = ""
GUARD = "the ultimate manager the Owner leans on"

def main():
    if not os.path.exists(TARGET):
        print("[ERROR] %s not found. Run from the dream-os repo root." % TARGET); sys.exit(1)
    with open(TARGET, "r", encoding="utf-8") as f:
        content = f.read()
    if GUARD in content:
        print("[SKIP] Myra soul already swapped to the authored rework."); return
    old = base64.b64decode(OLD_B64).decode("utf-8")
    new = base64.b64decode(NEW_B64).decode("utf-8")
    n = content.count(old)
    if n != 1:
        print("[ERROR] MYRA_SOUL block anchor found %d time(s) (expected 1). File UNTOUCHED." % n); sys.exit(1)
    content = content.replace(old, new)
    with open(TARGET, "w", encoding="utf-8") as f:
        f.write(content)
    print("[OK] Myra soul swapped (verbatim, opening on {{ASSISTANT_NAME}}). Builder/export/placeholder preserved.")
    print("     Gate: node --check src/agent/myraSoul.js")

if __name__ == "__main__":
    main()
